(function() {'use strict';function hideSkeletons() {var minDelay = 400;var startTime = window.skeletonStartTime || Date.now();var elapsed = Date.now() - startTime;var delay = Math.max(0, minDelay - elapsed);setTimeout(function() {document.querySelectorAll('[data-skeleton-target]').forEach(function(target) {target.classList.remove('skeleton-loading');target.classList.add('skeleton-loaded');});}, delay);}window.skeletonStartTime = Date.now();if (document.readyState === 'complete') {hideSkeletons();} else {window.addEventListener('load', hideSkeletons);}window.hideSkeletons = hideSkeletons;window.showSkeletons = function() {document.querySelectorAll('[data-skeleton-target]').forEach(function(target) {target.classList.remove('skeleton-loaded');target.classList.add('skeleton-loading');});window.skeletonStartTime = Date.now();};})();